#include <iostream>
using namespace std;

class Trie {
public:
    Trie* children[26];
    bool isEndOfWord;
    Trie() {isEndOfWord = false;}
    void insert(string word) {
        Trie* root = this;
        for (char ch : word) {
            int index = ch - 'a';
            if (root->children[index] == NULL) {
                root->children[index] = new Trie();
            }
            root = root->children[index];
        }
    }
};

int main() {
    int n = 0;
    cin >> n;
    string word;
    cin >> word;
    Trie t;
    t.insert(word);
    cout << (t.children[0] != NULL ? 'true' : 'false') << endl;
    return 0;
}
